  displaySuccess(skfFolder, ides = [], action = 'fresh') {
    // Build IDE name map from platform-codes.yaml
    const ideNames = { other: 'your IDE' };
    for (const p of getAvailablePlatforms()) {
      ideNames[p.value] = p.label;
    }

    let ideDisplay;
    if (!ides || ides.length === 0) {
      ideDisplay = 'your IDE';
    } else if (ides.length === 1) {
      ideDisplay = ideNames[ides[0]] || 'your IDE';
    } else {
      ideDisplay = ides.map((ide) => ideNames[ide] || ide).join(' or ');
    }

    let noteTitle;
    let noteBody;

    // Pick the invocation form based on selected IDEs:
    //   /skf-forger  — Claude Code slash command
    //   $skf-forger  — generic form for other agentic IDEs
    const hasClaudeCode = Array.isArray(ides) && ides.includes('claude-code');
    const hasOther = Array.isArray(ides) && ides.some((id) => id !== 'claude-code');
    let activateCmd;
    if (hasClaudeCode && !hasOther) {
      activateCmd = brand.gold('/skf-forger');
    } else if (hasOther && !hasClaudeCode) {
      activateCmd = brand.gold('$skf-forger');
    } else {
      activateCmd = `${brand.gold('/skf-forger')} ${chalk.dim('(Claude Code)')} ${chalk.dim('·')} ${brand.gold('$skf-forger')} ${chalk.dim('(others)')}`;
    }

    if (action === 'update') {
      noteTitle = brand.amber.bold('Update complete!');
      noteBody = [
        `${chalk.white.bold('What Changed')}`,
        'SKF files and agents have been refreshed.',
        'Your config.yaml and sidecar state are preserved.',
        '',
        `${chalk.white.bold('Next Steps')}`,
        `1. Reload the agent in ${ideDisplay}:  ${activateCmd}`,
        `2. Then run ${brand.gold('@Ferris SF')} to re-detect tools if needed`,
      ].join('\n');
    } else {
      noteTitle = brand.amber.bold('Installation complete!');
      noteBody = [
        `${chalk.white.bold('Get Started')}`,
        `1. Open this folder in ${ideDisplay}`,
        `2. Activate Ferris:  ${activateCmd}`,
        '3. Ferris (your Skill Architect) will guide you through',
        '   setting up and forging your first agent skill',
      ].join('\n');
    }

    note(noteBody, noteTitle);

    outro(
      `${brand.spark('⚒')}  Agent: ${chalk.white('Ferris')} ${chalk.dim('(Skill Architect & Integrity Guardian)')}\n${brand.dark('⚡')} Docs: ${brand.amber('https://armelhbobdad.github.io/bmad-module-skill-forge')}\n${brand.gold('▶')}  Call the forger:  ${activateCmd}`,
    );
  }
}

module.exports = { UI };

